const express = require('express');
const app = express();
const { URL } = require('url');

app.get('/auth/callback', (req, res) => {
    const returnUrl = req.query.return_url;

    if (!returnUrl) {
        return res.status(400).send('Return URL is required');
    }

    try {
        const parsedUrl = new URL(returnUrl);
        // Optionally, you can add additional checks to ensure the URL is safe
        if (parsedUrl.origin !== req.get('origin')) {
            return res.status(400).send('Invalid return URL');
        }
        // Handle successful authentication logic here

        res.redirect(returnUrl);
    } catch (error) {
        return res.status(400).send('Invalid return URL');
    }
});

app.listen(3000, () => {
    console.log('Server is running on port 3000');
});